/**
 * Analytics data models for the dashboard feature.
 *
 * These types define the shape of analytics data flowing through the system:
 * - Raw data points are collected from orders and users
 * - The AnalyticsService aggregates them into summaries
 * - Route handlers return the aggregated results
 *
 * Design note: TimeRange is used consistently across all query methods
 * to allow filtering by arbitrary date windows. The granularity field
 * controls how time-series data is bucketed (hourly, daily, weekly, monthly).
 */

// ---------------------------------------------------------------------------
// Query parameters
// ---------------------------------------------------------------------------

/**
 * Time range for filtering analytics data.
 * All analytics queries accept this to scope results to a window.
 */
export interface TimeRange {
  start: Date;
  end: Date;
}

/**
 * Granularity for time-series bucketing.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * Standard query parameters accepted by analytics endpoints.
 */
export interface AnalyticsQuery {
  timeRange: TimeRange;
  granularity: TimeGranularity;
}

// ---------------------------------------------------------------------------
// Time-series data
// ---------------------------------------------------------------------------

/**
 * A single point in a time series.
 * `timestamp` is the start of the bucket; `value` is the aggregate for that bucket.
 */
export interface TimeSeriesPoint {
  timestamp: Date;
  value: number;
}

/**
 * A named time series — e.g. "revenue" or "newUsers".
 */
export interface TimeSeries {
  label: string;
  points: TimeSeriesPoint[];
}

// ---------------------------------------------------------------------------
// Metric summaries
// ---------------------------------------------------------------------------

/**
 * The set of metric types the analytics service can produce.
 */
export type MetricType = 'revenue' | 'orders' | 'users' | 'average-order-value';

/**
 * Summary of a single metric over a time range.
 * `change` is the percentage change versus the previous period of equal length.
 */
export interface MetricSummary {
  type: MetricType;
  currentValue: number;
  previousValue: number;
  change: number;
  timeSeries: TimeSeries;
}

// ---------------------------------------------------------------------------
// Order analytics
// ---------------------------------------------------------------------------

/**
 * Breakdown of orders by their current status.
 */
export interface OrderStatusBreakdown {
  pending: number;
  confirmed: number;
  shipped: number;
  delivered: number;
  cancelled: number;
}

/**
 * Aggregated order analytics for a time range.
 */
export interface OrderAnalytics {
  totalOrders: number;
  totalRevenue: number;
  averageOrderValue: number;
  statusBreakdown: OrderStatusBreakdown;
  revenueSeries: TimeSeries;
  orderCountSeries: TimeSeries;
}

// ---------------------------------------------------------------------------
// User analytics
// ---------------------------------------------------------------------------

/**
 * Aggregated user analytics for a time range.
 */
export interface UserAnalytics {
  totalUsers: number;
  newUsers: number;
  usersByRole: Record<string, number>;
  newUserSeries: TimeSeries;
}

// ---------------------------------------------------------------------------
// Dashboard (top-level aggregate)
// ---------------------------------------------------------------------------

/**
 * Full dashboard payload combining all analytics sections.
 * This is what GET /api/analytics/dashboard returns.
 */
export interface DashboardData {
  generatedAt: Date;
  timeRange: TimeRange;
  metrics: MetricSummary[];
  orders: OrderAnalytics;
  users: UserAnalytics;
}

/**
 * Analytics service — aggregates order and user data into dashboard metrics.
 *
 * Depends on:
 * - OrderRepository (data layer) for reading order data
 * - UserRepository (data layer) for reading user data
 *
 * Architecture notes:
 * - This service is READ-ONLY — it never mutates data.
 * - All public methods accept an AnalyticsQuery to scope results by time range.
 * - Aggregation happens in-memory over repository data. If the dataset grows
 *   large, a future optimisation would be to pre-aggregate via event listeners
 *   (subscribe to order:created, order:status-changed, user:created events on
 *   the EventBus and maintain running counters).
 * - The service returns plain data objects; serialisation is the caller's
 *   responsibility.
 */

import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  OrderAnalytics,
  OrderStatusBreakdown,
  TimeSeries,
  TimeSeriesPoint,
  UserAnalytics,
} from '../models/analytics.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  // -------------------------------------------------------------------------
  // Public API
  // -------------------------------------------------------------------------

  /**
   * Build the full dashboard payload.
   *
   * Implementation guide:
   * 1. Fetch all orders and users from repositories
   * 2. Filter to the requested time range
   * 3. Compute each section (orders, users, metric summaries)
   * 4. Return a single DashboardData object
   */
  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
    this.logger.info('Building dashboard');

    const orders = this.getOrdersInRange(query);
    const users = this.getUsersInRange(query);

    const orderAnalytics = this.buildOrderAnalytics(orders, query);
    const userAnalytics = this.buildUserAnalytics(users, query);
    const metrics = this.buildMetricSummaries(orderAnalytics, userAnalytics, query);

    return {
      generatedAt: new Date(),
      timeRange: query.timeRange,
      metrics,
      orders: orderAnalytics,
      users: userAnalytics,
    };
  }

  /**
   * Get a single metric summary by type.
   *
   * Implementation guide:
   * 1. Compute only the data needed for the requested metric type
   * 2. Build time-series at the requested granularity
   * 3. Compute period-over-period change
   */
  async getMetric(type: MetricType, query: AnalyticsQuery): Promise<MetricSummary> {
    this.logger.info(`Building metric: ${type}`);

    const orders = this.getOrdersInRange(query);
    const users = this.getUsersInRange(query);
    const orderAnalytics = this.buildOrderAnalytics(orders, query);
    const userAnalytics = this.buildUserAnalytics(users, query);
    const metrics = this.buildMetricSummaries(orderAnalytics, userAnalytics, query);

    const metric = metrics.find((m) => m.type === type);
    if (!metric) {
      throw new Error(`Unknown metric type: ${type}`);
    }

    return metric;
  }

  /**
   * Get order-specific analytics.
   */
  async getOrderAnalytics(query: AnalyticsQuery): Promise<OrderAnalytics> {
    this.logger.info('Building order analytics');
    const orders = this.getOrdersInRange(query);
    return this.buildOrderAnalytics(orders, query);
  }

  /**
   * Get user-specific analytics.
   */
  async getUserAnalytics(query: AnalyticsQuery): Promise<UserAnalytics> {
    this.logger.info('Building user analytics');
    const users = this.getUsersInRange(query);
    return this.buildUserAnalytics(users, query);
  }

  // -------------------------------------------------------------------------
  // Data fetching helpers
  // -------------------------------------------------------------------------

  /**
   * Fetch all orders whose createdAt falls within the query time range.
   *
   * TODO: implement filtering — currently returns all orders.
   */
  private getOrdersInRange(query: AnalyticsQuery): Order[] {
    const allOrders = this.orderRepository.findAll();
    return allOrders.filter(
      (o) => o.createdAt >= query.timeRange.start && o.createdAt <= query.timeRange.end,
    );
  }

  /**
   * Fetch all users whose createdAt falls within the query time range.
   *
   * TODO: implement filtering — currently returns all users.
   */
  private getUsersInRange(query: AnalyticsQuery): User[] {
    const allUsers = this.userRepository.findAll();
    return allUsers.filter(
      (u) => u.createdAt >= query.timeRange.start && u.createdAt <= query.timeRange.end,
    );
  }

  // -------------------------------------------------------------------------
  // Aggregation stubs
  // -------------------------------------------------------------------------

  /**
   * Aggregate order data into OrderAnalytics.
   *
   * Implementation guide for the next developer:
   * 1. Sum `order.total` for totalRevenue
   * 2. Count orders for totalOrders
   * 3. Divide revenue / orders for averageOrderValue
   * 4. Group orders by status for statusBreakdown
   * 5. Bucket orders by granularity for revenueSeries and orderCountSeries
   *    (use `bucketByTime` helper once implemented)
   */
  private buildOrderAnalytics(_orders: Order[], _query: AnalyticsQuery): OrderAnalytics {
    // Stub — returns zeroed-out structure for compilation.
    // Next session should replace this with real aggregation.
    const emptySeries: TimeSeries = { label: '', points: [] };
    return {
      totalOrders: 0,
      totalRevenue: 0,
      averageOrderValue: 0,
      statusBreakdown: { pending: 0, confirmed: 0, shipped: 0, delivered: 0, cancelled: 0 },
      revenueSeries: { ...emptySeries, label: 'revenue' },
      orderCountSeries: { ...emptySeries, label: 'orders' },
    };
  }

  /**
   * Aggregate user data into UserAnalytics.
   *
   * Implementation guide for the next developer:
   * 1. Count all users for totalUsers (may want to consider all users, not just in-range)
   * 2. Count users created in the time range for newUsers
   * 3. Group by role for usersByRole
   * 4. Bucket new users by granularity for newUserSeries
   */
  private buildUserAnalytics(_users: User[], _query: AnalyticsQuery): UserAnalytics {
    const emptySeries: TimeSeries = { label: '', points: [] };
    return {
      totalUsers: 0,
      newUsers: 0,
      usersByRole: {},
      newUserSeries: { ...emptySeries, label: 'newUsers' },
    };
  }

  /**
   * Build the four top-level MetricSummary cards shown on the dashboard.
   *
   * Implementation guide for the next developer:
   * 1. For each MetricType, extract the current-period value from the
   *    already-computed orderAnalytics / userAnalytics.
   * 2. To compute `previousValue` and `change`, run the same aggregation
   *    over the *previous* period of equal length. For example, if the query
   *    spans 7 days, the previous period is the 7 days before that.
   * 3. `change` = ((current - previous) / previous) * 100, or 0 when
   *    previous is 0.
   * 4. Attach the relevant TimeSeries from orderAnalytics / userAnalytics.
   */
  private buildMetricSummaries(
    _orderAnalytics: OrderAnalytics,
    _userAnalytics: UserAnalytics,
    _query: AnalyticsQuery,
  ): MetricSummary[] {
    const metricTypes: MetricType[] = ['revenue', 'orders', 'users', 'average-order-value'];
    return metricTypes.map((type) => ({
      type,
      currentValue: 0,
      previousValue: 0,
      change: 0,
      timeSeries: { label: type, points: [] },
    }));
  }
}

/**
 * Analytics route handlers.
 *
 * This module defines the route structure for the analytics dashboard API.
 * Since the app has no HTTP framework (pure TypeScript), these are structured
 * as handler functions that accept parsed request params and return typed
 * response objects. A future HTTP layer (Express, Fastify, etc.) would wire
 * these handlers to actual endpoints.
 *
 * Route map:
 *   GET /api/analytics/dashboard       → getDashboardHandler
 *   GET /api/analytics/metrics/:type   → getMetricHandler
 *   GET /api/analytics/orders          → getOrderAnalyticsHandler
 *   GET /api/analytics/users           → getUserAnalyticsHandler
 */

import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  OrderAnalytics,
  TimeGranularity,
  UserAnalytics,
} from '../models/analytics.js';
import type { AnalyticsService } from '../services/analytics.service.js';

// ---------------------------------------------------------------------------
// Request / response types
// ---------------------------------------------------------------------------

/**
 * Raw query-string parameters before parsing.
 * These mirror what an HTTP framework would hand us.
 */
export interface AnalyticsQueryParams {
  startDate: string;   // ISO 8601
  endDate: string;     // ISO 8601
  granularity?: string; // defaults to 'day'
}

/**
 * Envelope shared by all analytics responses.
 */
export interface AnalyticsResponse<T> {
  success: boolean;
  data: T;
  error?: string;
}

// ---------------------------------------------------------------------------
// Param parsing
// ---------------------------------------------------------------------------

/**
 * Parse and validate raw query params into an AnalyticsQuery.
 * Throws on invalid input so callers can catch and return 400.
 */
export function parseAnalyticsQuery(params: AnalyticsQueryParams): AnalyticsQuery {
  const start = new Date(params.startDate);
  const end = new Date(params.endDate);

  if (isNaN(start.getTime())) {
    throw new Error('Invalid startDate');
  }
  if (isNaN(end.getTime())) {
    throw new Error('Invalid endDate');
  }
  if (start >= end) {
    throw new Error('startDate must be before endDate');
  }

  const validGranularities: TimeGranularity[] = ['hour', 'day', 'week', 'month'];
  const granularity = (params.granularity ?? 'day') as TimeGranularity;
  if (!validGranularities.includes(granularity)) {
    throw new Error(`Invalid granularity: ${params.granularity}. Must be one of: ${validGranularities.join(', ')}`);
  }

  return { timeRange: { start, end }, granularity };
}

// ---------------------------------------------------------------------------
// Handlers
// ---------------------------------------------------------------------------

/**
 * GET /api/analytics/dashboard
 *
 * Returns the full dashboard payload with all metric summaries,
 * order analytics, and user analytics for the requested time range.
 */
export async function getDashboardHandler(
  service: AnalyticsService,
  params: AnalyticsQueryParams,
): Promise<AnalyticsResponse<DashboardData>> {
  const query = parseAnalyticsQuery(params);
  const data = await service.getDashboard(query);
  return { success: true, data };
}

/**
 * GET /api/analytics/metrics/:type
 *
 * Returns a single MetricSummary for the given metric type.
 * :type is one of: revenue, orders, users, average-order-value
 */
export async function getMetricHandler(
  service: AnalyticsService,
  metricType: string,
  params: AnalyticsQueryParams,
): Promise<AnalyticsResponse<MetricSummary>> {
  const validTypes: MetricType[] = ['revenue', 'orders', 'users', 'average-order-value'];
  if (!validTypes.includes(metricType as MetricType)) {
    return {
      success: false,
      data: undefined as unknown as MetricSummary,
      error: `Invalid metric type: ${metricType}. Must be one of: ${validTypes.join(', ')}`,
    };
  }

  const query = parseAnalyticsQuery(params);
  const data = await service.getMetric(metricType as MetricType, query);
  return { success: true, data };
}

/**
 * GET /api/analytics/orders
 *
 * Returns order-specific analytics (totals, status breakdown, time series).
 */
export async function getOrderAnalyticsHandler(
  service: AnalyticsService,
  params: AnalyticsQueryParams,
): Promise<AnalyticsResponse<OrderAnalytics>> {
  const query = parseAnalyticsQuery(params);
  const data = await service.getOrderAnalytics(query);
  return { success: true, data };
}

/**
 * GET /api/analytics/users
 *
 * Returns user-specific analytics (totals, role breakdown, new-user series).
 */
export async function getUserAnalyticsHandler(
  service: AnalyticsService,
  params: AnalyticsQueryParams,
): Promise<AnalyticsResponse<UserAnalytics>> {
  const query = parseAnalyticsQuery(params);
  const data = await service.getUserAnalytics(query);
  return { success: true, data };
}
